//! Auto-generated by the spec-word-compliance workflow for area
//! "Multi-column layout (cols/col) and document grid (docGrid)".
//!
//! Each `#[test]` encodes a Word-consumption / schema-validity / serializer
//! rule mined from ISO 29500-1 §17.6.3-§17.6.5, the MS-OI29500 implementer
//! notes, and the transitional WML schema (CT_Columns / CT_Column /
//! CT_DocGrid). A FAILING assertion means stemma diverges from Word — that is
//! a real Word-compliance gap, NOT something to make pass by weakening the
//! test.
//!
//! Methodology note (consumption vs. save): stemma round-trips untouched
//! content byte-verbatim, so `reserialize()` of an unedited document reflects
//! stemma's verbatim-preservation contract, not Word's render-time
//! normalization. xmlContains/xmlOmits/order assertions here are therefore
//! restricted to child ORDERING and structural validity; "Word ignores value
//! V on layout" rules are asserted on the READ side (accept/reject text) or
//! via opens-clean, never on the re-serialized XML.

use std::io::Read;

use stemma::ExportOptions;
use stemma::api::{Document, validate};

// ─── Prelude ────────────────────────────────────────────────────────────────

/// Build a valid minimal .docx. `body_xml` is the inner contents of
/// `<w:body>…</w:body>`. `extra_parts` are additional `(part_path, xml)` pairs
/// (e.g. `("word/styles.xml", "<w:styles…>")`) that also receive a
/// `[Content_Types].xml` override.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-type overrides for the known extra parts.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (path, _) in extra_parts {
        let ct = if path.ends_with("styles.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
        } else if path.ends_with("numbering.xml") {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
        } else {
            "application/xml"
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/{path}" ContentType="{ct}"/>"#
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#;

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (path, xml) in extra_parts {
            zip.start_file(*path, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a .docx and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive =
        zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx zip for document.xml");
    let mut file = archive
        .by_name("word/document.xml")
        .expect("word/document.xml present in package");
    let mut s = String::new();
    file.read_to_string(&mut s).expect("read document.xml");
    s
}

/// Parse → serialize(default) → return the re-emitted `word/document.xml`.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reserialize");
    let out = doc
        .serialize(&ExportOptions::default())
        .expect("serialize for reserialize");
    document_xml_of(&out)
}

/// Opens-clean: stemma's validity check reports no errors.
fn assert_opens_clean(bytes: &[u8], msg: &str) {
    let report = validate(bytes);
    assert!(
        report.ok && report.issues.is_empty(),
        "{msg} — but validate() reported issues: {:?}",
        report.issues
    );
}

// ─── Tests ──────────────────────────────────────────────────────────────────

#[test]
fn cols_sep_accepts_st_onoff_literal_true() {
    let body = r#"<w:p><w:r><w:t>Separator rule body</w:t></w:r></w:p><w:sectPr><w:cols w:num="2" w:space="720" w:sep="true"/></w:sectPr>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.6.4 + §17.17.4 + §22.9.2.7: w:cols/@w:sep is ST_OnOff and the literal 'true' is a valid on-value, so sep=\"true\" is schema-valid and must open clean",
    );
}

#[test]
fn docgrid_linepitch_st_decimalnumber_large_value_layout_only() {
    let body = r#"<w:p><w:r><w:t>Grid line pitch body</w:t></w:r></w:p><w:sectPr><w:docGrid w:type="lines" w:linePitch="32767"/></w:sectPr>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.6.5 + §17.18.10: docGrid/@w:linePitch is ST_DecimalNumber (unbounded integer); a large value is schema-valid and must open clean",
    );
    let accepted = Document::parse(&b)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text();
    assert_eq!(
        accepted.trim(),
        "Grid line pitch body",
        "ISO 29500-1 §17.6.5: linePitch is a layout-only per-line pitch; the accepted text is exactly the body paragraph regardless of pitch value"
    );
}

#[test]
fn last_col_omitted_space_serialized_as_zero() {
    let body = r#"<w:p><w:r><w:t>Two unequal columns, last has no space.</w:t></w:r></w:p><w:sectPr><w:pgSz w:w="12240" w:h="15840"/><w:cols w:num="2" w:equalWidth="0"><w:col w:w="2640" w:space="720"/><w:col w:w="6000"/></w:cols></w:sectPr>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "ECMA-376 §17.6.3 + MS-OI29500 §2.1.212 + Annex A CT_Column: the last column's space is ignored and the schema default for col space is 0, so the file is schema-valid and Word opens without repair",
    );
}

