#[test]
fn cols_serializer_emits_explicit_col_space_on_rebuild() {
    let body = r#"<w:p><w:r><w:t>Unequal columns, last col space omitted.</w:t></w:r></w:p><w:sectPr><w:cols w:num="2" w:equalWidth="0"><w:col w:w="4000" w:space="480"/><w:col w:w="5000"/></w:cols></w:sectPr>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "ECMA-376 §17.6.3 + MS-OI29500 §2.1.212 + Annex A CT_Column: both col elements carry the required w:w under equalWidth=\"0\", so Word opens the file without repair",
    );
}

#[test]
fn equalwidth_omitted_no_num_with_col_children_is_single_column() {
    let body = r#"<w:p><w:r><w:t>Single column body text.</w:t></w:r></w:p><w:sectPr><w:cols><w:col w:w="2400"/><w:col w:w="4800"/></w:cols></w:sectPr>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "MS-OI29500 §2.1.213 + ISO 29500-1 §17.6.4: omitted equalWidth defaults true and omitted num is assumed 1, so the col children are inert; the section is a well-formed single column Word opens without repair",
    );
    let accepted = Document::parse(&b)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text();
    assert_eq!(
        accepted.trim(),
        "Single column body text.",
        "ISO 29500-1 §17.6.4: column geometry (num/col children) is layout-only and never alters the text stream; accepted text equals the authored prose"
    );
}

#[test]
fn last_col_space_ignored_does_not_alter_text_or_validity() {
    let body = r#"<w:p><w:r><w:t>Two unequal columns.</w:t></w:r></w:p><w:sectPr><w:cols w:equalWidth="0"><w:col w:w="2640" w:space="720"/><w:col w:w="6000" w:space="720"/></w:cols></w:sectPr>"#;
    let b = make_docx(body, &[]);
    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.6.3 + §17.6.4 + MS-OI29500 §2.1.212: trailing-column space is ignored (not malformed), so Word opens the document without repair",
    );
    let accepted = Document::parse(&b)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text();
    assert_eq!(
        accepted.trim(),
        "Two unequal columns.",
        "ISO 29500-1 §17.6.3: an ignored trailing-column space is layout-only and cannot change the text stream; accepted text equals the authored prose"
    );
}

